module RefModule(
    input [7:0] input_x,
    input [7:0] input_y,
    output [7:0] output_sum,
    output [7:0] output_and,
    output [7:0] output_cmp
    );  wire _n01 = input_x[0] ^ input_y[0];
  wire _c01 = input_x[0] & input_y[0];
  wire _n02 = input_x[1] ^ input_y[1] ^ _c01;
  wire _c02 = (input_x[1] & input_y[1]) | (input_x[1] & _c01) | (input_y[1] & _c01);
  wire _n03 = input_x[2] ^ input_y[2] ^ _c02;
  wire _c03 = (input_x[2] & input_y[2]) | (input_x[2] & _c02) | (input_y[2] & _c02);
  wire _n04 = input_x[3] ^ input_y[3] ^ _c03;
  wire _c04 = (input_x[3] & input_y[3]) | (input_x[3] & _c03) | (input_y[3] & _c03);
  assign output_sum = {_n01, _n02, _n03, _n04};
assign output_and = input_x & input_y;
assign output_cmp = (input_x == 8'b0) ? 8'b1 : 8'b0; 

endmodule
